+/// strictly case-sensitive on POSIX systems).
+pub fn lookup_shadow_by_name(content: &[u8], name: &[u8]) -> Option<ShadowEntry> {
+    for line in content.split(|&b| b == b'\n') {
+        if let Some(entry) = parse_shadow_line(line)
+            && entry.name == name
+        {
+            return Some(entry);
+        }
+    }
+    None
