+fn strip_trailing_eol(s: &[u8]) -> &[u8] {
+    let mut end = s.len();
+    while end > 0 && (s[end - 1] == b'\n' || s[end - 1] == b'\r') {
+        end -= 1;
+    }
+    &s[..end]
+}
+
+fn trim_leading_ws(s: &[u8]) -> &[u8] {
+    let start = s
+        .iter()
+        .position(|&b| b != b' ' && b != b'\t')
+        .unwrap_or(s.len());
+    &s[start..]
+}

